// Basic validation & normalization
const item = $json;
const required = ['requestId', 'requesterName', 'department', 'amount'];
let invalid = false;
for (const field of required) {
  if (!item[field] || item[field] === '') invalid = true;
}
return [{
  json: {
    ...item,
    invalid,
    timestamp: new Date().toISOString()
  }
}];

// Simple router: choose approver by department
const dept = $json.department;
let approverEmail = 'user@example.com';
if (dept === 'Finance') approverEmail = 'user@example.com';
if (dept === 'HR') approverEmail = 'user@example.com';
return [{ json: { ...$json, approverEmail } }];
